 45→func TestUploadHandler_MissingFile(t *testing.T) {
 46→	// We can't easily test with a real storage.Client without S3,
 47→	// so this tests the handler logic up to the storage call.
 48→	// The handler requires a non-nil storage to proceed past the first check.
 49→	// For unit tests, we test the MIME validation and key generation via
 50→	// the mimeFromFilename helper and allowedAudioTypes map.
