112→func TestUploadHandler_BadContentType(t *testing.T) {
113→	// Create a multipart request with a non-audio file
114→	var buf bytes.Buffer
115→	w := multipart.NewWriter(&buf)
116→	part, err := w.CreateFormFile("file", "test.txt")
117→	if err != nil {
118→		t.Fatal(err)
119→	}
120→	_, _ = part.Write([]byte("not audio"))
121→	_ = w.Close()
122→
123→	// We need a non-nil storage to get past the first check.
124→	// Since we can't easily create a mock storage.Client (it's a struct, not an interface),
125→	// we test the content type validation logic indirectly through the types map.
126→	// The full integration test would require a running S3.
127→}
