  1→package storage
  2→
  3→import (
  4→	"context"
  5→	"errors"
  6→	"fmt"
  7→	"io"
  8→	"time"
  9→
 10→	"github.com/aws/aws-sdk-go-v2/aws"
 11→	awsconfig "github.com/aws/aws-sdk-go-v2/config"
 12→	"github.com/aws/aws-sdk-go-v2/credentials"
 13→	"github.com/aws/aws-sdk-go-v2/service/s3"
 14→	"github.com/aws/aws-sdk-go-v2/service/s3/types"
 15→)
 16→
 17→// Config holds the S3-compatible storage configuration.
 18→type Config struct {
 19→	Endpoint       string
 20→	Bucket         string
 21→	AccessKey      string
 22→	SecretKey      string
 23→	Region         string
 24→	ForcePathStyle bool
 25→}
 26→
 27→// Client wraps an S3 client for object storage operations.
 28→type Client struct {
 29→	s3Client      *s3.Client
 30→	presignClient *s3.PresignClient
 31→	bucket        string
 32→}
 33→
 34→// New creates an S3 storage client from the given config.
 35→func New(cfg Config) (*Client, error) {
 36→	if cfg.Bucket == "" {
 37→		return nil, fmt.Errorf("storage: bucket name is required")
 38→	}
 39→
 40→	opts := []func(*awsconfig.LoadOptions) error{
 41→		awsconfig.WithRegion(cfg.Region),
 42→	}
 43→
 44→	if cfg.AccessKey != "" && cfg.SecretKey != "" {
 45→		opts = append(opts, awsconfig.WithCredentialsProvider(
 46→			credentials.NewStaticCredentialsProvider(cfg.AccessKey, cfg.SecretKey, ""),
 47→		))
 48→	}
 49→
 50→	awsCfg, err := awsconfig.LoadDefaultConfig(context.Background(), opts...)
 51→	if err != nil {
 52→		return nil, fmt.Errorf("storage: load aws config: %w", err)
 53→	}
 54→
 55→	s3Opts := []func(*s3.Options){}
 56→	if cfg.Endpoint != "" {
 57→		s3Opts = append(s3Opts, func(o *s3.Options) {
 58→			o.BaseEndpoint = aws.String(cfg.Endpoint)
 59→		})
 60→	}
 61→	if cfg.ForcePathStyle {
 62→		s3Opts = append(s3Opts, func(o *s3.Options) {
 63→			o.UsePathStyle = true
 64→		})
 65→	}
 66→
 67→	client := s3.NewFromConfig(awsCfg, s3Opts...)
 68→
 69→	return &Client{
 70→		s3Client:      client,
 71→		presignClient: s3.NewPresignClient(client),
 72→		bucket:        cfg.Bucket,
 73→	}, nil
 74→}
 75→
 76→// Upload uploads content to S3 at the given key.
 77→func (c *Client) Upload(ctx context.Context, key string, body io.Reader, contentType string) error {
 78→	input := &s3.PutObjectInput{
 79→		Bucket:      aws.String(c.bucket),
 80→		Key:         aws.String(key),
 81→		Body:        body,
 82→		ContentType: aws.String(contentType),
 83→	}
 84→
 85→	if _, err := c.s3Client.PutObject(ctx, input); err != nil {
 86→		return fmt.Errorf("storage: upload %q: %w", key, err)
 87→	}
 88→	return nil
 89→}
 90→
 91→// Download retrieves content from S3 at the given key.
 92→func (c *Client) Download(ctx context.Context, key string) (io.ReadCloser, error) {
 93→	output, err := c.s3Client.GetObject(ctx, &s3.GetObjectInput{
 94→		Bucket: aws.String(c.bucket),
 95→		Key:    aws.String(key),
 96→	})
 97→	if err != nil {
 98→		return nil, fmt.Errorf("storage: download %q: %w", key, err)
 99→	}
100→	return output.Body, nil
101→}
102→
103→// Delete removes an object from S3.
104→func (c *Client) Delete(ctx context.Context, key string) error {
105→	if _, err := c.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
106→		Bucket: aws.String(c.bucket),
107→		Key:    aws.String(key),
108→	}); err != nil {
109→		return fmt.Errorf("storage: delete %q: %w", key, err)
110→	}
111→	return nil
112→}
113→
114→// Exists checks if an object exists at the given key.
115→func (c *Client) Exists(ctx context.Context, key string) (bool, error) {
116→	_, err := c.s3Client.HeadObject(ctx, &s3.HeadObjectInput{
117→		Bucket: aws.String(c.bucket),
118→		Key:    aws.String(key),
119→	})
120→	if err != nil {
121→		var notFound *types.NotFound
122→		if errors.As(err, &notFound) {
123→			return false, nil
124→		}
125→		return false, fmt.Errorf("storage: exists %q: %w", key, err)
126→	}
127→	return true, nil
128→}
129→
130→// PresignedURL generates a pre-signed URL for temporary read access.
131→func (c *Client) PresignedURL(ctx context.Context, key string, expiry time.Duration) (string, error) {
132→	req, err := c.presignClient.PresignGetObject(ctx, &s3.GetObjectInput{
133→		Bucket: aws.String(c.bucket),
134→		Key:    aws.String(key),
135→	}, s3.WithPresignExpires(expiry))
136→	if err != nil {
137→		return "", fmt.Errorf("storage: presign %q: %w", key, err)
138→	}
139→	return req.URL, nil
140→}
