 13→
 14→func TestWhisperAPIProvider_Transcribe(t *testing.T) {
 15→	t.Run("success", func(t *testing.T) {
 16→		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 17→			// Verify request
 18→			if r.Method != http.MethodPost {
 19→				t.Errorf("expected POST, got %s", r.Method)
 20→			}
 21→			if !strings.HasPrefix(r.Header.Get("Content-Type"), "multipart/form-data") {
 22→				t.Errorf("expected multipart/form-data content type")
 23→			}
 24→			if r.Header.Get("Authorization") != "Bearer test-key" {
 25→				t.Errorf("expected Bearer test-key, got %s", r.Header.Get("Authorization"))
 26→			}
 27→
 28→			// Verify multipart fields
 29→			if err := r.ParseMultipartForm(10 << 20); err != nil {
 30→				t.Fatalf("parse multipart: %v", err)
 31→			}
 32→			if r.FormValue("model") != "whisper-1" {
 33→				t.Errorf("expected model whisper-1, got %s", r.FormValue("model"))
 34→			}
 35→			if r.FormValue("language") != "en" {
 36→				t.Errorf("expected language en, got %s", r.FormValue("language"))
 37→			}
 38→			file, _, err := r.FormFile("file")
 39→			if err != nil {
 40→				t.Fatalf("expected file field: %v", err)
 41→			}
 42→			_ = file.Close()
 43→
 44→			w.Header().Set("Content-Type", "application/json")
 45→			_ = json.NewEncoder(w).Encode(whisperResponse{Text: "Hello, world!"})
 46→		}))
 47→		defer srv.Close()
 48→
 49→		p := NewWhisperAPI("test-key", WithBaseURL(srv.URL))
 50→		text, err := p.Transcribe(context.Background(), strings.NewReader("fake audio"), TranscribeOpts{
 51→			Language: "en",
 52→			Format:   "wav",
 53→		})
 54→		if err != nil {
 55→			t.Fatalf("unexpected error: %v", err)
 56→		}
 57→		if text != "Hello, world!" {
 58→			t.Errorf("expected 'Hello, world!', got %q", text)
 59→		}
 60→	})
 61→
 62→	t.Run("api error", func(t *testing.T) {
 63→		srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
 64→			http.Error(w, `{"error":"invalid api key"}`, http.StatusUnauthorized)
 65→		}))
 66→		defer srv.Close()
