  1→package provider
  2→
  3→import (
  4→	"bytes"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"mime/multipart"
 10→	"net/http"
 11→)
 12→
 13→const defaultWhisperModel = "whisper-1"
 14→const defaultWhisperBaseURL = "https://api.openai.com/v1"
 15→
 16→// WhisperAPIProvider transcribes audio via the OpenAI Whisper API.
 17→type WhisperAPIProvider struct {
 18→	apiKey  string
 19→	model   string
 20→	baseURL string
 21→	client  *http.Client
 22→}
 23→
 24→// NewWhisperAPI creates a WhisperAPIProvider using the given API key.
 25→func NewWhisperAPI(apiKey string, opts ...WhisperAPIOption) *WhisperAPIProvider {
 26→	p := &WhisperAPIProvider{
 27→		apiKey:  apiKey,
 28→		model:   defaultWhisperModel,
 29→		baseURL: defaultWhisperBaseURL,
 30→		client:  http.DefaultClient,
 31→	}
 32→	for _, o := range opts {
 33→		o(p)
 34→	}
 35→	return p
 36→}
 37→
 38→// WhisperAPIOption configures a WhisperAPIProvider.
 39→type WhisperAPIOption func(*WhisperAPIProvider)
 40→
 41→// WithModel sets the Whisper model name.
 42→func WithModel(model string) WhisperAPIOption {
 43→	return func(p *WhisperAPIProvider) { p.model = model }
 44→}
 45→
 46→// WithBaseURL overrides the API base URL (useful for testing).
 47→func WithBaseURL(url string) WhisperAPIOption {
 48→	return func(p *WhisperAPIProvider) { p.baseURL = url }
 49→}
 50→
 51→// WithHTTPClient sets a custom HTTP client.
 52→func WithHTTPClient(c *http.Client) WhisperAPIOption {
 53→	return func(p *WhisperAPIProvider) { p.client = c }
 54→}
 55→
 56→// whisperResponse is the JSON response from the OpenAI transcription endpoint.
 57→type whisperResponse struct {
 58→	Text string `json:"text"`
 59→}
 60→
 61→// Transcribe sends audio to the OpenAI Whisper API and returns the transcript.
 62→func (p *WhisperAPIProvider) Transcribe(ctx context.Context, audio io.Reader, opts TranscribeOpts) (string, error) {
 63→	var buf bytes.Buffer
 64→	w := multipart.NewWriter(&buf)
 65→
 66→	// model field
 67→	if err := w.WriteField("model", p.model); err != nil {
 68→		return "", fmt.Errorf("provider: whisper api: write model field: %w", err)
 69→	}
 70→
 71→	// optional language
 72→	if opts.Language != "" {
 73→		if err := w.WriteField("language", opts.Language); err != nil {
 74→			return "", fmt.Errorf("provider: whisper api: write language field: %w", err)
 75→		}
 76→	}
 77→
 78→	// audio file part
 79→	filename := "audio"
 80→	if opts.Format != "" {
 81→		filename = "audio." + opts.Format
 82→	}
 83→	part, err := w.CreateFormFile("file", filename)
 84→	if err != nil {
 85→		return "", fmt.Errorf("provider: whisper api: create form file: %w", err)
 86→	}
 87→	if _, err := io.Copy(part, audio); err != nil {
 88→		return "", fmt.Errorf("provider: whisper api: copy audio: %w", err)
 89→	}
 90→	if err := w.Close(); err != nil {
 91→		return "", fmt.Errorf("provider: whisper api: close multipart: %w", err)
 92→	}
 93→
 94→	url := p.baseURL + "/audio/transcriptions"
 95→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, &buf)
 96→	if err != nil {
 97→		return "", fmt.Errorf("provider: whisper api: create request: %w", err)
 98→	}
 99→	req.Header.Set("Authorization", "Bearer "+p.apiKey)
100→	req.Header.Set("Content-Type", w.FormDataContentType())
101→
102→	resp, err := p.client.Do(req)
103→	if err != nil {
104→		return "", fmt.Errorf("provider: whisper api: request: %w", err)
105→	}
106→	defer func() { _ = resp.Body.Close() }()
107→
108→	if resp.StatusCode != http.StatusOK {
109→		body, _ := io.ReadAll(io.LimitReader(resp.Body, 1024))
110→		return "", fmt.Errorf("provider: whisper api: status %d: %s", resp.StatusCode, string(body))
111→	}
112→
113→	var result whisperResponse
114→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
115→		return "", fmt.Errorf("provider: whisper api: decode response: %w", err)
116→	}
117→
118→	if result.Text == "" {
119→		return "", fmt.Errorf("provider: whisper api: empty transcript")
120→	}
121→
122→	return result.Text, nil
123→}
