package router

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"path/filepath"
	"strings"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/storage"
)

// allowedAudioTypes maps MIME types to file extensions for audio uploads.
var allowedAudioTypes = map[string]string{
	"audio/mpeg":  "mp3",
	"audio/wav":   "wav",
	"audio/x-wav": "wav",
	"audio/ogg":   "ogg",
	"audio/webm":  "webm",
	"audio/mp4":   "m4a",
	"audio/x-m4a": "m4a",
	"audio/flac":  "flac",
}

type uploadResponse struct {
	Key         string `json:"key"`
	ContentType string `json:"content_type"`
	Size        int64  `json:"size"`
}

func uploadHandler(store *storage.Client, maxSize int64) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if store == nil {
			http.Error(w, "object storage not configured", http.StatusServiceUnavailable)
			return
		}

		claims := auth.GetClaims(r.Context())
		if claims == nil {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}

		// Limit request body size
		r.Body = http.MaxBytesReader(w, r.Body, maxSize)

		if err := r.ParseMultipartForm(maxSize); err != nil {
			http.Error(w, "file too large or invalid form data", http.StatusBadRequest)
			return
		}
		defer func() {
			if r.MultipartForm != nil {
				_ = r.MultipartForm.RemoveAll()
			}
		}()

		file, header, err := r.FormFile("file")
		if err != nil {
			http.Error(w, "missing file field", http.StatusBadRequest)
			return
		}
		defer func() { _ = file.Close() }()

		// Validate MIME type
		contentType := header.Header.Get("Content-Type")
		if contentType == "" {
			// Try to detect from filename
			contentType = mimeFromFilename(header.Filename)
		}
		ext, ok := allowedAudioTypes[contentType]
		if !ok {
			http.Error(w, fmt.Sprintf("unsupported audio type: %s", contentType), http.StatusBadRequest)
			return
		}

		// Generate upload key
		uploadID := uuid.New()
		key := fmt.Sprintf("%s/uploads/%s.%s", claims.UserID, uploadID, ext)

		// Upload to S3
		if err := store.Upload(r.Context(), key, file, contentType); err != nil {
			slog.ErrorContext(r.Context(), "router: upload: s3 upload failed",
				"key", key,
				"error", err,
			)
			http.Error(w, "upload failed", http.StatusInternalServerError)
			return
		}

		slog.InfoContext(r.Context(), "router: upload: completed",
			"key", key,
			"size", header.Size,
			"content_type", contentType,
		)

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(uploadResponse{
			Key:         key,
			ContentType: contentType,
			Size:        header.Size,
		})
	}
}

func mimeFromFilename(name string) string {
	ext := strings.ToLower(filepath.Ext(name))
	switch ext {
	case ".mp3":
		return "audio/mpeg"
	case ".wav":
		return "audio/wav"
	case ".ogg":
		return "audio/ogg"
	case ".webm":
		return "audio/webm"
	case ".m4a":
		return "audio/mp4"
	case ".flac":
		return "audio/flac"
	default:
		return ""
	}
}

