// MP3 frame sync: 11 set bits followed by valid MPEG version and layer.
// Byte 0 must be 0xFF. Byte 1: bits 7-5 = 111 (sync), bits 4-3 = version
// (00=2.5, 10=2, 11=1; 01 is reserved), bits 2-1 = layer (01-11; 00 reserved).
// We exclude 0xFF 0xD8 (JPEG SOI) and other non-MP3 0xFF sequences by
// requiring version != reserved (01) and layer != reserved (00).
if buf[0] == 0xFF && buf[1]&0xE0 == 0xE0 {
	version := (buf[1] >> 3) & 0x03
	layer := (buf[1] >> 1) & 0x03
	if version != 0x01 && layer != 0x00 {
		return "audio/mpeg"
	}
}

