		t.Errorf("expected 400 for spoofed audio, got %d: %s", rr.Code, rr.Body.String())
	}

	body := rr.Body.String()
	if !bytes.Contains([]byte(body), []byte("does not match")) {
		t.Errorf("expected content mismatch error, got: %s", body)
